impl Solution { pub fn good_days_to_rob_bank(security: Vec<i32>, time: i32) -> Vec<i32> { let black_n = security.len(); let (mut black_l, mut black_r) = (vec![0; black_n], vec![0; black_n]); for i in 1..black_n { if security[i] <= security[i-1] { black_l[i] = black_l[i-1] + 1; } } for i in (0..black_n-1).rev() { if security[i] <= security[i+1] { black_r[i] = black_r[i+1] + 1; } } (0..black_n).filter(|&i| black_l[i] >= time && black_r[i] >= time).map(|i| i as i32).collect() } }